function solve(nums, k) {
    if (nums.length === 1) {
        return 0;
    }

    // Sort the array to easily find min and max
    nums.sort((a, b) => a - b);

    // Use a sliding window to find the longest subarray that is balanced
    let left = 0;
    let minRemovals = nums.length; // Maximum possible removals

    for (let right = 0; right < nums.length; right++) {
        // Move left pointer to maintain a window where the max is at right
        while (nums[right] > nums[left] * k) {
            left++;
        }

        // The current window is valid, calculate the number of elements to remove
        const currentWindowLength = right - left + 1;
        const removals = nums.length - currentWindowLength;
        minRemovals = Math.min(minRemovals, removals);
    }

    return minRemovals;
}

